UPDATE users SET organization_id = (SELECT id FROM organizations LIMIT 1) WHERE organization_id IS NULL AND NOT EXISTS (SELECT 1 from organizations limit 1); INSERT into organizations (id, name, slug, organization_type, is_active, is_deleted, owner_id) SELECT gen_random_uuid(), 'Default Workspace', 'default-workspace', 'COMPANY', true, false, id from users where organization_id is null LIMIT 1 ON CONFLICT DO NOTHING; UPDATE users SET organization_id = (SELECT id FROM organizations LIMIT 1) WHERE organization_id IS NULL;
